-- دفعة ثانية من الشبهات — موضوعان آمنان إضافيان (يرفع الإجمالي من 4
-- إلى 6). ما زلت أؤجّل عمدًا: سنّ عائشة رضي الله عنها، الرق، حدّ
-- الردة، تفاصيل فقه الجهاد الدقيقة — تستحق تأليف عالم شرعي متخصص.
-- status='draft'، is_approved=false إلزاميًا.
INSERT INTO dawah_shubuhat (category_id, slug, title, complexity_level, shubha_text, why_spread, short_answer, detailed_refutation, assumption_correction, historical_linguistic_context, evidences, sources, objections_and_responses, conclusion, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='jihad'), 'quran-violence-verses-context',
'ألا تدعو آيات القتال في القرآن إلى العنف المطلق ضد غير المسلمين؟', 'advanced',
'"القرآن مليء بآيات تأمر بقتل الكفار وغير المسلمين أينما وُجدوا، وهذا دليل على أن الإسلام دين عنيف بطبيعته."',
'تنتشر هذه الشبهة غالبًا عبر اقتباس جزء من آية بمعزل عن سياقها الكامل (كجزء من آية ٥ سورة التوبة "فاقتلوا المشركين") دون ذكر ما قبلها وبعدها من قيود وسياق تاريخي محدد، وهو أسلوب اقتباس منتقٍ منتشر في الخطاب المعادي للإسلام.',
'آيات القتال في القرآن نزلت في سياقات تاريخية محددة (رد عدوان، أو نقض عهد من طرف معيّن بذاته)، لا كأمر عام مطلق بقتال كل غير مسلم في كل زمان ومكان — وقراءة السياق الكامل للآية المقتبسة غالبًا تكشف هذا القيد بوضوح.',
'خذ المثال الأشهر: آية "فاقتلوا المشركين حيث وجدتموهم" (التوبة: ٥) غالبًا ما تُقتبَس منفردة. لكن سياقها الكامل يوضح أنها تتحدث تحديدًا عن مشركين معيّنين نقضوا عهدًا مبرمًا مع المسلمين واعتدوا عليهم، والآيات المحيطة بها (قبلها وبعدها في نفس السورة) تنص صراحة على استثناء من التزم بعهده ولم ينقضه، بل تأمر بحمايته حتى وهو مشرك: "وَإِنْ أَحَدٌ مِّنَ الْمُشْرِكِينَ اسْتَجَارَكَ فَأَجِرْهُ حَتَّىٰ يَسْمَعَ كَلَامَ اللَّهِ ثُمَّ أَبْلِغْهُ مَأْمَنَهُ" (التوبة: ٦). هذا السياق يقلب الاستدلال المتسرع رأسًا على عقب: الآية نفسها التي تُقتبَس كدليل على "عنف مطلق" تحتوي في محيطها المباشر أمرًا بحماية غير المسلم المسالم. القاعدة الأصولية الراسخة عند علماء التفسير هي عدم فهم أي آية بمعزل عن سياقها القرآني والتاريخي الكامل (أسباب النزول)، وهذا مبدأ منهجي، لا استثناء دفاعي مُختلَق لتبرير النص.',
'الافتراض الخاطئ هو معاملة آية مقتبسة جزئيًا كأنها قانون عام مطلق بلا سياق، بينما المنهج العلمي السليم في تفسير أي نص (ديني أو قانوني أو أدبي) يقتضي دومًا فهمه ضمن سياقه الكامل قبل الحكم عليه.',
'الآيات التي تتحدث عن القتال في القرآن غالبًا ما تُقرَن بذكر سبب محدد (نقض عهد، عدوان بدأ به الطرف الآخر، إخراج من الديار)، وهو ما يُعرَف في علوم القرآن بـ"أسباب النزول" — فهم هذا السياق التاريخي شرط منهجي أساسي لفهم دلالة الآية الفعلية، لا تفصيل ثانوي يمكن تجاهله.',
'[{"type":"quran","ref":"التوبة: ٦","text":"وَإِنْ أَحَدٌ مِّنَ الْمُشْرِكِينَ اسْتَجَارَكَ فَأَجِرْهُ حَتَّىٰ يَسْمَعَ كَلَامَ اللَّهِ ثُمَّ أَبْلِغْهُ مَأْمَنَهُ ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌ لَّا يَعْلَمُونَ"}, {"type":"quran","ref":"البقرة: ١٩٠","text":"وَقَاتِلُوا فِي سَبِيلِ اللَّهِ الَّذِينَ يُقَاتِلُونَكُمْ وَلَا تَعْتَدُوا ۚ إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"أليس هذا مجرد تبرير لاحق لتخفيف وقع الآية؟","response":"لا — قاعدة قراءة النص ضمن سياقه (أسباب النزول، السياق التاريخي، الآيات المحيطة) منهج تفسيري راسخ وقديم جدًا في علوم القرآن سابق لأي جدل معاصر، وهو نفس المنهج الذي يُطبَّق على فهم أي نص قانوني أو تاريخي آخر في العالم، لا استثناء مُختلَق لهذه الآية بعينها."}]'::jsonb,
'قراءة آيات القتال ضمن سياقها الكامل (لا مقتطفة) تكشف أنها مقيَّدة بأسباب محددة (عدوان، نقض عهد) لا أمرًا عامًا مطلقًا بقتال كل غير مسلم — وهذا يتطلب دائمًا الرجوع لسياق الآية الكامل قبل الحكم عليها.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='sharia'), 'islam-incompatible-with-modernity',
'هل الإسلام دين متجمد لا يناسب العصر الحديث؟', 'basic',
'"الإسلام دين وُضع لمجتمع صحراوي قبل ١٤٠٠ عام، ولا يمكن أن يصلح لعصر التقنية والفضاء وحقوق الإنسان الحديثة."',
'تنتشر هذه الشبهة من ملاحظة تفاصيل معينة في الفقه القديم بدت مرتبطة بسياق زمني محدد، مع إغفال المساحة الاجتهادية الواسعة في الشريعة القادرة على التفاعل مع كل عصر، والخلط بين ثوابت العقيدة (التي لا تتغير بطبيعتها كأي نظام قيمي) وتفاصيل فقهية متغيرة بطبيعتها.',
'التمييز الأساسي: الإسلام يحوي ثوابت عقدية وأخلاقية لا تتغير بتغير الزمن (لأنها مرتبطة بحقائق ثابتة كوجود الله وكرامة الإنسان)، ومساحة اجتهادية فقهية واسعة جدًا صُممت أصلًا لتتفاعل مع كل عصر ومستجداته.',
'من الخطأ المنهجي مقارنة الإسلام بـ"قانون مدني جامد" لا يقبل التطور. الشريعة الإسلامية بُنيت من أساسها على تمييز بين المقاصد الثابتة (حفظ الدين، النفس، العقل، النسل، المال) والوسائل المتغيرة لتحقيقها. فالمقصد الثابت هو العدل مثلًا، أما وسيلة تحقيقه في التقاضي أو المعاملات المالية فتتطور بتطور أدوات العصر (كالتحكيم الإلكتروني أو العقود الرقمية) عبر اجتهاد فقهي مستمر. تاريخيًا، أنتج هذا المرونة الاجتهادية مذاهب فقهية متعددة تجاوبت مع بيئات وأزمنة مختلفة جدًا (من الأندلس إلى آسيا الوسطى)، وهذا دليل عملي على قدرة الشريعة على التفاعل مع سياقات متنوعة جدًا لا الجمود على صورة واحدة. أما مسائل حقوق الإنسان الحديثة تحديدًا، فكثير من مبادئها الجوهرية (كرامة الإنسان، حرمة الدم، العدل) موجودة في النص الإسلامي التأسيسي نفسه منذ البداية، وإن اختلفت صياغتها المعاصرة المؤسساتية.',
'الافتراض الخاطئ هو اختزال "الإسلام" في تفاصيل فقهية جزئية مرتبطة بسياق تاريخي معين، وتعميمها على الدين كله وكأنها ثوابت جامدة، بينما بنية الشريعة نفسها مصممة للتمييز بين الثابت والمتغير.',
NULL,
'[]'::jsonb,
'[]'::jsonb,
'[{"objection":"لكن هناك تفاصيل فقهية قديمة لا تزال تُطبَّق حرفيًا في بعض البلدان دون مراعاة تطور العصر.","response":"هذا خلاف في الاجتهاد والتطبيق بين علماء ومؤسسات مختلفة، لا حكمًا نهائيًا واحدًا يمثل الإسلام كله — نفس المسألة الفقهية قد يُجتهَد فيها باجتهادات مختلفة معاصرة، وهذا التنوع نفسه دليل على مرونة البنية الفقهية لا جمودها."}]'::jsonb,
'الإسلام يميّز بين ثوابت عقدية وأخلاقية لا تتغير، ومساحة اجتهادية فقهية واسعة صُممت أصلًا للتفاعل مع كل عصر — وهذا التمييز هو ما يفسر استمرار تطبيقه الفعلي عبر عصور وبيئات متنوعة جدًا دون جمود.',
'draft', false)
